const weather = $('Weather').first().json.current;

const WMO = {
  0: 'céu limpo',
  1: 'parcialmente nublado', 2: 'parcialmente nublado',
  3: 'céu encoberto',
  45: 'neblina', 48: 'neblina',
  51: 'garoa', 53: 'garoa', 55: 'garoa',
  61: 'chuva fraca', 63: 'chuva moderada', 65: 'chuva forte',
  66: 'chuva congelante', 67: 'chuva congelante',
  71: 'neve', 73: 'neve', 75: 'neve',
  80: 'pancadas de chuva', 81: 'pancadas de chuva', 82: 'pancadas de chuva',
  95: 'trovoada', 96: 'trovoada', 99: 'trovoada'
};
const weather_phrase = WMO[weather.weather_code] || 'condição indefinida';

const todaySP = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Sao_Paulo' });
const events = $('Events Read').all().map(i => i.json);
const todays = events.filter(e => String(e.date) === todaySP);
const events_list = todays.length === 0
  ? 'Nenhum evento registrado hoje.'
  : todays.map(e => `- ${e.date} ${e.time} ${e.event_name} (${e.location})`).join('\n');

// Derive deterministic facts so the LLM doesn't have to infer them.
const is_raining = (weather.rain > 0) || (weather.precipitation > 0) || [51,53,55,61,63,65,66,67,80,81,82].includes(weather.weather_code);
const is_hot = weather.temperature_2m >= 28;
const is_cold = weather.temperature_2m <= 12;
const is_windy = weather.wind_speed_10m >= 30;
const is_stormy = [95,96,99].includes(weather.weather_code);

const advice_rules = [];
if (is_raining) advice_rules.push('- Há chuva ou garoa agora: recomende levar guarda-chuva ou capa.');
if (!is_raining) advice_rules.push('- NÃO há chuva. NÃO mencione guarda-chuva, chuva ou proteção contra chuva.');
if (is_cold) advice_rules.push('- Temperatura baixa: recomende agasalho.');
if (is_hot) advice_rules.push('- Temperatura alta: recomende hidratação.');
if (!is_cold && !is_hot) advice_rules.push('- Temperatura amena: NÃO recomende agasalho nem reforço de hidratação.');
if (is_windy) advice_rules.push('- Vento forte (>30 km/h): alerte sobre o vento.');
if (!is_windy) advice_rules.push('- Vento fraco/moderado: NÃO mencione vento como fator relevante.');
if (is_stormy) advice_rules.push('- ALERTA: há trovoada. Inclua alerta de risco claro.');
if (!is_stormy && !is_raining && !is_windy) advice_rules.push('- Sem riscos meteorológicos: indique explicitamente que não há alertas hoje.');

const payload = {
  city: 'Curitiba',
  weather_time: weather.time,
  temperature: weather.temperature_2m,
  humidity: weather.relative_humidity_2m,
  rain: weather.rain,
  precipitation: weather.precipitation,
  wind_speed: weather.wind_speed_10m,
  weather_phrase,
  weather_code: weather.weather_code,
  events_list,
  is_raining, is_hot, is_cold, is_windy, is_stormy
};

const prompt = `Você é o CampusCast AI. Produza um boletim curto em português do Brasil para estudantes, estritamente fiel aos dados.

### DADOS (fonte única da verdade — não invente nada fora daqui)
Cidade: ${payload.city}
Horário: ${payload.weather_time}
Condição atual: ${payload.weather_phrase} (código WMO ${payload.weather_code})
Temperatura: ${payload.temperature} °C
Umidade: ${payload.humidity}%
Chuva (mm na última hora): ${payload.rain}
Precipitação total (mm): ${payload.precipitation}
Vento: ${payload.wind_speed} km/h

### EVENTOS DO CAMPUS HOJE
${payload.events_list}

### REGRAS DE CONTEÚDO (obrigatórias)
${advice_rules.join('\n')}

### ESTRUTURA
1. Saudação breve (1 frase).
2. Resumo do clima (1 frase) usando APENAS a 'Condição atual' e a temperatura — sem adjetivar o que não está nos dados.
3. Conselho prático: siga as regras de conteúdo acima. NÃO adicione conselhos que não foram autorizados pelas regras.
4. Lembrete de eventos: cite cada evento listado. Se a lista disser "Nenhum evento registrado hoje", diga isso com estas palavras.
5. Alerta final: se as regras autorizarem um alerta, inclua-o; caso contrário, escreva exatamente "Sem alertas de risco para hoje."

### REGRAS GLOBAIS
- Máximo de 120 palavras.
- Português claro, natural, adequado para leitura em áudio.
- PROIBIDO: asteriscos (*), sublinhados (_), crases, hashtags (#), emojis, qualquer marcação markdown. O texto será lido em voz alta — todo caractere de marcação será pronunciado literalmente e soará péssimo.
- Produza APENAS prosa corrida. Sem títulos, sem negrito, sem listas com bullets. Não escreva 'Boletim CampusCast' em negrito ou como cabeçalho; se precisar de um título, escreva uma frase normal.
- NÃO invente eventos, clima, nem riscos. Se os dados não cobrem um tópico, não o mencione.
- NÃO faça suposições sobre a hora do dia além do que o campo 'Horário' diz.`;

return [{ json: { payload, prompt } }];
